<template>
    <v-container fluid class="pa-6 pt-4 fill-height train-data-manage">
      <v-row no-gutters class="fill-height">
        <v-sheet width="100%" height="33">
          <h3 class="font-weight-bold">{{ title }}</h3>
        </v-sheet>
        <v-sheet width="100%" height="calc(100% - 32px)" class="pt-2 overflow-hidden cctv-roi-manage-contents">
          <v-row no-gutters class="pa-0 fill-height">
            <v-card width="170" color="login_bg" class="pa-2 fill-height red">
              <v-list nav dense style="max-height: 1116px;
                                      overflow-y: auto;
                                      background: #eef2f5;">
                <v-list-item-group v-model="selected" color="primary" class="login_bg">
                  <template v-for="(item, i) in list">
                    <v-list-item :key="item.cctv_id" :disabled="item.cctv_id == selected" :input-value="item.cctv_id" :value="item.cctv_id" class="login_bg" @click="onCCTV(item)">
                      <v-list-item-content>
                        <v-list-item-title v-text="`${item.camera_nm}(${item.camera_desc})`" class="text-subtitle-2" />
                      </v-list-item-content>
                    </v-list-item>
                  </template>
                </v-list-item-group>
              </v-list>
            </v-card>
            <v-col class="ml-4 fill-height overflow-x-hidden overflow-y-auto">
              <v-sheet width="100%" height="40px" class="d-flex align-center" style="justify-content: space-between;">
                <v-sheet style="display: flex; align-items: center">
                  <v-col class="pa-0 ma-0"> 
                    <span>{{ `이미지 수집 주기 :` }}</span>
                  </v-col>
                  <v-radio-group v-model="collection_period" row class="pl-2 pt-0">
                    <v-radio 
                      color="radio" 
                      v-for="(item, index) in collectCycleList" 
                      :key="index" 
                      :label="$t(item.text)" 
                      :value="item.value"
                      @change="changeCycle(item.value)"
                    >
                  </v-radio>
                  </v-radio-group>
                </v-sheet>
                <v-sheet>
                  {{ `서버 용량 : ${usedServerStorage} / ${totalServerStorage}[GB] (${storagePerPercent.toFixed(2)}%)` }}
                </v-sheet>
              </v-sheet>
              <v-card width="100%" style="height: calc(100% - 40px)" outlined rounded="md" class="pa-3 px-5">
                <v-sheet height="33" style="display: flex; justify-content: space-between; align-items: center;">
                  <h4 v-if="nonData_chk" class="font-weight-bold">
                    {{ `수집 상태 : ${startDt} ~ ${endDt} 기간, ${totalImage}장` }}
                  </h4>
                  <h4 v-if="!nonData_chk" class="font-weight-bold">
                    {{ `수집 상태 : 현재 수집된 데이터 없음` }}
                  </h4>
                  <v-sheet class="pa-0 ma-0">
                    <template v-for="button in headerButton">
                      <v-btn
                        :key="button.id"
                        height="30"
                        color="btn_bg"
                        class="mr-2 px-0"
                        elevation="0"
                        outlined
                        rounded
                        small
                        :width="button.text ? 120 : 35"
                        @click="button.onClick"
                      >
                        <div class="font-weight-bold content--text">
                          <template v-if="button.text">
                            <span class="ml-1">{{ $t(button.text) }}</span>
                          </template>
                        </div>
                      </v-btn>
                    </template>
                  </v-sheet>
                </v-sheet>
                <v-sheet width="100%" min-width="700" height="calc(100% - 33px - 70px)" class="pt-1" ref="roiContainer">
                  <template v-if="!isLoading">
                    <v-row no-gutters class="align-center justify-center fill-height">
                      <v-progress-circular indeterminate color="secondary" />
                    </v-row>
                  </template>
                  <template v-else>
                    <v-row no-gutters class="fill-height">
                      <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
                        <i-card-vertical :headerTitle="$t('압축파일 리스트')" device="web">
                          <template v-slot:body>
                            <v-layout column>
                              <v-col cols="12" lg="12" class="pa-0 ">
                                <DxDataGrid
                                  id="trainDataGrid"
                                  class="layout-col-height00"
                                  width="100%"
                                  :ref="dxDataGridRef"
                                  :data-source="gridMain"
                                  :remote-operations="false"
                                  :hover-state-enabled="true"
                                  :allow-column-resizing="true"
                                  :allow-column-reordering="true"
                                  :row-alternation-enabled="true"
                                  :column-auto-width="false"
                                  :column-hiding-enabled="true"
                                  :show-borders="true"
                                  :show-row-lines="true"
                                  :focused-row-enabled="true"
                                  key-expr="create_zip_date"
                                >
                                  <DxColumn
                                    data-field="create_zip_date"
                                    :caption="$t('생성일자')"
                                    width="200px"
                                    alignment="center"
                                    data-type="date"
                                    format="yyyy.MM.dd HH:mm"
                                    :allow-editing="false"
                                  >
                                  </DxColumn>

                                  <DxColumn 
                                    data-field="file_name" 
                                    :caption="$t('파일명')" 
                                    width="500px"
                                    data-type="string" 
                                    alignment="center" 
                                    :allow-editing="false"
                                  />

                                  <DxColumn 
                                    data-field="file_size_gb" 
                                    :caption="$t('용량(GB)')" 
                                    width="150px"
                                    data-type="number" 
                                    alignment="right" 
                                    :allow-editing="false"
                                    :format="{ type: 'fixedPoint', precision: 2 }"
                                  />

                                  <DxColumn
                                    cell-template="manage"
                                    :caption="$t('관리')"
                                    width="150px"
                                    alignment="center"
                                    :allow-editing="false"
                                  />
                                  <template #manage="{ data:cellInfo }">
                                    <v-row no-gutters>
                                      <v-col>
                                        <v-btn
                                          elevation="0"
                                          color="btn_sub"
                                          dark
                                          x-small
                                          @click="fileDownload(cellInfo)"
                                        >
                                          다운로드
                                        </v-btn>
                                        <v-btn 
                                          elevation="0" 
                                          color="btn_sub" 
                                          dark 
                                          x-small 
                                          class="ml-1" 
                                          role="delete" 
                                          @click="fileDelete(cellInfo)">
                                          삭제
                                        </v-btn>
                                      </v-col>
                                    </v-row>
                                  </template>
                                </DxDataGrid>
                              </v-col>
                            </v-layout>
                          </template>
                        </i-card-vertical>
                      </v-col>
                    </v-row>
                  </template>
                </v-sheet>
              </v-card>
            </v-col>
          </v-row>
          <span class="cctv-roi-manage-contents-mobile">해당 화면은 모바일 환경에서 지원되지 않습니다.</span>
        </v-sheet>
      </v-row>
      
      <v-dialog v-model="downloadDialog" persistent width="min-content" min-width="50vw" >
        <v-card class="pa-4" style="height: 10vh; width: 30vw;">
          <v-card-title class="pa-0 pb-4 text-subtitle-1 font-weight-bold primary--text">
            <span class="text-body-1 font-weight-bold">{{ '다운로드 진행율' }}</span>
            <v-spacer />
            <span class="text-body-1 font-weight-bold grey--text">{{ downloadProgress + '%' }}</span>
          </v-card-title>
          <v-sheet width="100%" height="calc(100% - 51px - 44px)">
            <v-card-text class="pa-0 d-flex align-center justify-center fill-height">
              <template>
                <v-progress-linear
                  :value="downloadProgress"
                  color="blue"
                  height="10"
                  class="mt-2"
                />
              </template>
            </v-card-text>
          </v-sheet>
          <v-card-actions class="pr-0 pb-0">
          <v-spacer />
          <v-btn style="margin-top: 10px;" small text outlined height="35" width="70" color="primary" @click="cancelDownload()">
            {{ $t('btnClose') }}
          </v-btn>
        </v-card-actions>
        </v-card>
    </v-dialog>
    </v-container>
  </template>
  
  <script>
  import axios from 'axios'
  import { DxDataGrid, DxColumn } from 'devextreme-vue/data-grid'
  import { DxFileUploader } from 'devextreme-vue/file-uploader'
  import { getUserCd } from '@/utils/token'
  import { getRoiList } from '@/api/realTimeVideoSafetyManagement/safetyMonitoringZoneManage.js'
  import { getRemoteServerCap, getRemoteDataState, createRemoteZip, deleteRemoteImages, getRemoteZipList, deleteRemoteZip, downloadRemoteZip} from '@/api/realTimeVideoSafetyManagement/TrainDataManage.js'
  import iCardVertical from '@/components/common/iCardVertical.vue'

  import baseview from '@/views/base/baseview.vue'
  import { param } from 'jquery'
  import { refresh } from 'less'
  export default {
    mixins: [baseview],
    name: 'TrainDataManage',
    components: {
      DxDataGrid,
      DxColumn,
      DxFileUploader,
      'i-card-vertical': iCardVertical,
    },
    data() {
      return {
        title: this.$t('trainDataManage'),
        selected: null,
        selectedItem: {},
        list: [],
        legacyList: [],
        isLoading: true,
        downloadProgress: 0, // 다운로드 진행률
        cancelTokenSource: null, // 요청 취소 토큰
        downloadDialog: false,
        //이미지 수집 주기
        collection_period: 'short',
        collectCycleList: [
          { text: '10분', value: 'short' },
          { text: '1시간', value: 'long' },
          { text: '자동(변화감지캡쳐)', value: 'auto' },
        ],
        //서버 용량
        usedServerStorage : 0,
        totalServerStorage : 0,

        //버튼 리스트
        headerButton : [
          { id: 'onRefresh', text: '새로고침', onClick: () => this.onRefresh() },
          { id: 'createZip', text: '압축파일 생성', onClick: () => this.createZip() },
          { id: 'deleteImage', text: '이미지 삭제', onClick: () => this.deleteImage() },
        ],
          
        //수집 상태
        nonData_chk : false,
        startDt: '2025-01-14 04:00',
        endDt : '2026-01-20 16:00',
        totalImage : '36000',

        //DataGrid
        dxDataGridRef: 'trainDataGrid',
        gridMain: [
          // {
          //   create_zip_date: '2025-01-14 15:59:22.517', 
          //   file_name: 'backup_CAM0016_20250114155922_20250114161912.zip',
          //   file_size_gb: 0  
          // },

        ],
      }
    },
    computed: {
      storagePerPercent () {
        return this.usedServerStorage / this.totalServerStorage * 100
      }
    },
    async mounted() {
      await this.onMounted()
    },
    watch: {
    },
    methods: {
      onMounted() {
        
        //Roi 대신 학습 데이터 관련 api 연동 필요
        getRoiList()
          .then(res => {
            this.list = res.list.map(el => {
              const { model_list, ...rest } = el
              return {
                ...rest,
              }
            })
            this.legacyList = JSON.parse(JSON.stringify(this.list))
            if(this.list.length !== 0) {
              this.selected = this.list[0].cctv_id
              this.selectedItem = this.list[0]
              if(this.selected == null) {
                this.selected = this.list[0].cctv_id
                this.selectedItem = this.list[0]
              } else {
                this.selectedItem = this.list.find(el => el.cctv_id == this.selected)
              }
              const param = {
                camera_id: this.selected,
                collection_period: this.collection_period
              }
              this.handleServerStorage(param)
              this.handleImgList(param)
              this.handleZipList(param) 
            }
          })
      },
      
      onCCTV(param) {
        this.selected = param.cctv_id
        this.selectedItem = param
        this.collection_period = 'short'
        const param0 = {
          camera_id: this.selected,
          collection_period: this.collection_period
        }
        this.handleServerStorage(param0)
        this.handleImgList(param0)
        this.handleZipList(param0) 
      },
      //서버 용량 확인
      handleServerStorage(param) {
        getRemoteServerCap(param).then(res => {
          this.usedServerStorage = res.disk.used_tb * 1000
          this.totalServerStorage = res.disk.total_tb * 1000
        })
      },
      //새로고침
      onRefresh() {
        const param = {
              camera_id: this.selected,
              collection_period: this.collection_period
        }
        this.handleServerStorage(param)
        this.handleImgList(param)
        this.handleZipList(param) 
      },
      //압축 파일 생성성
      createZip() {
        const param = {
          camera_id: this.selected,
          collection_period: this.collection_period
        }
        // console.log('압축 파일 생성 버튼')
        if(!this.nonData_chk) {
          this.$vToastify.prompt({ body: '압축 할 데이터가 없습니다.', answers: { 확인: true } })
          return
        }
        createRemoteZip(param).then(res => {
          // console.log(res)
          if(res.message == "Successfully created zip on remote server") {
            this.$vToastify.prompt({ body: '압축 파일 생성중 잠시 후에 새로고침 해서 확인', answers: { 확인: true } })
          } else {
            this.$vToastify.prompt({ body: '압축 할 데이터가 없습니다.', answers: { 확인: true } })
          }
        })
      },
      //이미지 삭제
      deleteImage() {
        console.log('이미지 삭제 버튼')
        if(!this.nonData_chk) {
          this.$vToastify.prompt({ body: '삭제 할 데이터가 없습니다.', answers: { 확인: true } })
          return
        }
        this.vToastifyPrompt(
            this.$t('수집된 이미지 데이터를 삭제하시겠습니까?'),
              'info',
            current => {
              //삭제 진행
              const param0 = {
                camera_id: this.selected,
                collection_period: this.collection_period
              }

              deleteRemoteImages(param0).then(
                res => {
                  console.log(res)
                  if(res.message=='Successfully deleted images on remote server') {
                    this.handleImgList(param0)
                  }
                })
            }, null, true)
      },

      //압축 파일 리스트 조회
      handleZipList(param) {
        console.log("압축파일 리스트 호출", this.selected, this.collection_period)
        getRemoteZipList(param).then(res => {
          console.log(res)
          if(res.msg=='성공하였습니다.'){
            this.gridMain = res.zip_files
          } else {
            this.gridMain = []
          }
        })
      },
      //이미지 파일 리스트 조회
      handleImgList(param) {
        getRemoteDataState(param).then(res => {
          console.log(res)
          if(res.code == 200) {
            if(res.msg == '성공하였습니다.'){
              this.nonData_chk = true
              this.startDt = res.start_collect;
              this.endDt = res.end_collect;
              this.totalImage = res.total_img;
            } else {
              this.nonData_chk = false
            }
          }
        }).catch(error => {
            console.error('getRemoteDataState Error', error)
            this.nonData_chk = false
        })
      },
      //이미지 수집 주기 변경
      changeCycle(param) {
        console.log("이미지 수집 주기 변경", param)
        const param0 = {
                camera_id: this.selected,
                collection_period: param
              }
        this.handleImgList(param0)
        this.handleZipList(param0)
      },
      //파일 다운로드
      async fileDownload(param) {
        this.downloadProgress = 0; // 진행률 초기화
        this.cancelTokenSource = axios.CancelToken.source(); // 새로운 취소 토큰 생성
        // console.log("파일 다운로드". param)
        try {
          // 서버에서 바이너리 데이터를 수신
          const response = await axios.post("/cctv/dt_crud_remote/download_remote_zip/" + this.selected, 
          {
            collection_period: this.collection_period,
            file_name: param.row.cells[1].value
          },
          {
            responseType: "blob", // Blob 형식으로 응답 받기
            cancelToken: this.cancelTokenSource.token, // 취소 토큰 추가
            onDownloadProgress: (progressEvent) => {
                if (progressEvent.lengthComputable) {
                  this.downloadDialog = true
                  this.downloadProgress = Math.round(
                    (progressEvent.loaded / progressEvent.total) * 100
                  );
                }
              },
            }
          );

          // Content-Disposition에서 파일명 추출
          const contentDisposition = response.headers["content-disposition"];
          const fileName = contentDisposition
            ? contentDisposition.match(/filename="?(.+?)"?$/)[1]
            : "downloaded_file";

          // Blob 객체를 사용해 브라우저에서 파일 다운로드
          const link = document.createElement("a");
          link.href = URL.createObjectURL(response.data);
          link.download = fileName;
          link.click();
          
          // 다운로드 완료 후 초기화
          this.downloadDialog = false
          this.downloadProgress = 0;
          this.cancelTokenSource = null;
          } catch (error) {
            if (axios.isCancel(error)) {
              console.warn("파일 다운로드가 취소되었습니다.");
            } else {
              console.error("파일 다운로드 오류:", error);
            }
            this.downloadDialog = false
            this.downloadProgress = 0;
            this.cancelTokenSource = null;
          }
      },
      cancelDownload() {
        if (this.cancelTokenSource) {
          this.cancelTokenSource.cancel("사용자가 다운로드를 취소하였습니다.");
          this.cancelTokenSource = null;
          this.downloadProgress = 0;
        }
      },
      //파일 삭제
      fileDelete(param) {
        console.log("파일 삭제" ,param)
        this.vToastifyPrompt(
            this.$t(param.row.cells[1].value + ' 파일을 삭제하시겠습니까?'),
              'info',
            current => {
              //삭제 진행
              console.log('삭제 진행')
              const param0 = {
                camera_id: this.selected,
                collection_period: this.collection_period,
                file_name: param.row.cells[1].value
              }

              deleteRemoteZip(param0).then(
                res => {
                  console.log(res)
                  if(res.code==200) {
                    //zip록록 리로드드
                    this.handleZipList(param0)
                  }
                })
            }, null, true)
      }

    },
  }
  </script>
  
  <style lang="scss">
  .train-data-manage {
    > div {
      position: relative;
      .v-list-item--dense, .v-list--dense .v-list-item {
        min-height: 36px !important;
        padding: 0 8px !important;
        margin-bottom: 8px !important;
      }
    }
    .divider-col-left {
      border-left: 1px solid #ebebeb;
    }
    .pointer-label {
      font-size: 18px;
      font-weight: 600;
    }
    &-contents {
      &-image {
        max-height: calc(100vh - 328px) !important;
        overflow: auto;
        > div {
          transform-origin: left top;
          width: 100%;
          height: 100%;
        }
        &-info {
          position: absolute;
          left: 0;
          bottom: 0;
          margin-left: 16px;
          margin-bottom: 8px;
        }
      }
      @media (max-width: 960px) {
        > div:first-child {
          display: none;
        }
        > div:not(:first-child) {
          display: block;
        }
      }
    }
  
  }
  </style>
